<?php namespace App\Repositories\Asset;use App\Repositories\BaseRepository;use App\Models\Asset\AssetMaintenance;use Illuminate\Database\Eloquent\Collection;class AssetMaintenanceRepository extends BaseRepository{    public function __construct(AssetMaintenance $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByAsset(int $assetId): Collection    {        return $this->findByField('asset_id', $assetId);    }    public function findByType(string $type): Collection    {        return $this->findByField('maintenance_type', $type);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('maintenance_date', [$startDate, $endDate])->get();    }    public function getPendingMaintenance(): Collection    {        return $this->query()->where('status', 'pending')->get();    }    public function getScheduledMaintenance(): Collection    {        return $this->query()->where('maintenance_date', '>=', now())->whereIn('status', ['scheduled', 'pending'])->get();    }    public function getOverdueMaintenance(): Collection    {        return $this->query()->where('maintenance_date', '<', now())->where('status', '!=', 'completed')->get();    }    public function searchMaintenance(string $keyword): Collection    {        return $this->query()->where('description', 'like', "%{$keyword}%")->orWhere('remarks', 'like', "%{$keyword}%")->get();    }    public function getByVendor(string $vendor): Collection    {        return $this->findByField('vendor', $vendor);    }    public function getByCostRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('cost', [$min, $max])->get();    }    public function scheduleMaintenance(array $data): AssetMaintenance    {        return $this->create($data);    }    public function completeMaintenance(int $id, array $data = []): bool    {        $updateData = array_merge($data, [            'status' => 'completed',            'completed_at' => now(),        ]);        return $this->update($id, $updateData);    }    public function getTotalMaintenanceCost(int $assetId): float    {        return $this->query()->where('asset_id', $assetId)->where('status', 'completed')->sum('cost');    }}